<script setup>
import { computed } from 'vue'

const props = defineProps({
  listing: { type: Object, required: true }
})

const fullAddress = computed(() => {
  const a = props.listing.address
  if (!a) return 'Address not available'
  const parts = [
    a.streetNumber, a.streetDirectionPrefix, a.streetName,
    a.streetSuffix, a.unitNumber ? '#' + a.unitNumber : null,
    a.neighborhood ? ', ' + a.neighborhood : null,
    a.city, a.state, a.zip
  ].filter(Boolean)
  return parts.join(' ').replace(/\s+/g, ' ').trim()
})

const formattedPrice = computed(() => {
  const price = props.listing.listPrice
  if (price == null) return '$0'
  return props.listing.type === 'Lease'
    ? '$' + price.toLocaleString() + '/mo'
    : '$' + price.toLocaleString()
})

const sqft = computed(() => {
  const s = props.listing.details?.sqft
  return s ? parseInt(s).toLocaleString() : null
})

const acres = computed(() => {
  const a = props.listing.lot?.acres
  if (a != null) return a
  const sq = props.listing.lot?.squareFeet
  return sq ? (sq / 43560).toFixed(2) : null
})

const mainImage = computed(() => {
  const images = props.listing.images
  if (!images?.length) return 'https://via.placeholder.com/500x350?text=No+Image'
  const img = images[0]
  return img.startsWith('http') ? img : 'https://cdn.repliers.io/' + img
})

const qualityLabel = computed(() => {
  const q = props.listing.imageInsights?.summary?.quality?.qualitative?.overall
  if (q) return q.toUpperCase()
  const status = props.listing.standardStatus
  if (status === 'Active') return 'ACTIVE'
  if (status === 'Sold') return 'SOLD'
  return 'LISTING'
})
</script>

